INSERT INTO quizzes (id, "languageCode", level, question, options, answer, explain, "quizOrder", "createdAt", "updatedAt") VALUES ('q-gen-en-4-in', 'en', 'A1', 'What is the meaning of "in"?', '["obtainable or accessible and ready for use or service","a very light colorless element that is one of the six inert gasses; the most difficult gas to liquefy; occurs in economi...","activity directed toward making or doing something","a unit of length equal to one twelfth of a foot"]'::jsonb, 3, '"in" means: a unit of length equal to one twelfth of a foot', 0, NOW(), NOW()) ON CONFLICT (id) DO UPDATE SET "languageCode" = EXCLUDED."languageCode", level = EXCLUDED.level, question = EXCLUDED.question, options = EXCLUDED.options, answer = EXCLUDED.answer, explain = EXCLUDED.explain, "quizOrder" = EXCLUDED."quizOrder", "updatedAt" = NOW();
INSERT INTO quizzes (id, "languageCode", level, question, options, answer, explain, "quizOrder", "createdAt", "updatedAt") VALUES ('q-gen-en-6-is', 'en', 'A1', 'What is the meaning of "is"?', '["everything that exists anywhere","a way of regarding situations or topics etc.","have the quality of being; (copula, used with an adjective or a predicate noun)","—"]'::jsonb, 2, '"is" means: have the quality of being; (copula, used with an adjective or a predicate noun)', 1, NOW(), NOW()) ON CONFLICT (id) DO UPDATE SET "languageCode" = EXCLUDED."languageCode", level = EXCLUDED.level, question = EXCLUDED.question, options = EXCLUDED.options, answer = EXCLUDED.answer, explain = EXCLUDED.explain, "quizOrder" = EXCLUDED."quizOrder", "updatedAt" = NOW();
INSERT INTO quizzes (id, "languageCode", level, question, options, answer, explain, "quizOrder", "createdAt", "updatedAt") VALUES ('q-gen-en-7-on', 'en', 'A1', 'What is the meaning of "on"?', '["people who are free","in operation or operational","a plan of action adopted by an individual or social group","the momentary present"]'::jsonb, 1, '"on" means: in operation or operational', 2, NOW(), NOW()) ON CONFLICT (id) DO UPDATE SET "languageCode" = EXCLUDED."languageCode", level = EXCLUDED.level, question = EXCLUDED.question, options = EXCLUDED.options, answer = EXCLUDED.answer, explain = EXCLUDED.explain, "quizOrder" = EXCLUDED."quizOrder", "updatedAt" = NOW();
INSERT INTO quizzes (id, "languageCode", level, question, options, answer, explain, "quizOrder", "createdAt", "updatedAt") VALUES ('q-gen-en-9-by', 'en', 'A1', 'What is the meaning of "by"?', '["where you live at a particular time","so as to pass a given point","one or some or every or all without specification","(superlative of `many'' used with count nouns and often preceded by `the'') quantifier meaning the greatest in number"]'::jsonb, 1, '"by" means: so as to pass a given point', 3, NOW(), NOW()) ON CONFLICT (id) DO UPDATE SET "languageCode" = EXCLUDED."languageCode", level = EXCLUDED.level, question = EXCLUDED.question, options = EXCLUDED.options, answer = EXCLUDED.answer, explain = EXCLUDED.explain, "quizOrder" = EXCLUDED."quizOrder", "updatedAt" = NOW();
INSERT INTO quizzes (id, "languageCode", level, question, options, answer, explain, "quizOrder", "createdAt", "updatedAt") VALUES ('q-gen-en-13-it', 'en', 'A1', 'What is the meaning of "it"?', '["a state in northwestern United States on the Pacific","located farther aft","the branch of engineering that deals with the use of computers and telecommunications to retrieve and store and transmit...","where you live at a particular time"]'::jsonb, 2, '"it" means: the branch of engineering that deals with the use of computers and telecommunications to retrieve and store and transmit...', 4, NOW(), NOW()) ON CONFLICT (id) DO UPDATE SET "languageCode" = EXCLUDED."languageCode", level = EXCLUDED.level, question = EXCLUDED.question, options = EXCLUDED.options, answer = EXCLUDED.answer, explain = EXCLUDED.explain, "quizOrder" = EXCLUDED."quizOrder", "updatedAt" = NOW();
